INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('07ee9eb6d82effc004631e27','venue','207','getting-there',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Walk if you''re a student. If you''re not, take the Tar Heel Express shuttle for $5 round trip.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('cc5b588b76c11bde5dcf4909','venue','207','getting-there',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Driving is the last resort, but parking is only $10 to $12.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('9254d7cf68afdb7731649b47','venue','207','getting-there',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Doors open 90 minutes before tip.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('0c7169d09e71fd1e83ad13e5','venue','207','before',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Top of the Hill: rooftop bar with occasional UNC star sightings.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('abbb1206520d44ad45eeb934','venue','207','before',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','He''s Not Here: 32oz blue cups (beer or seltzer) for $5, rated a top-10 bar in the US by The Athletic.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('fd88d09f71b05eaa69cc6404','venue','207','before',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Sup Dogs: game-day bar food, affordable and always hits.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('bc4dd110494da130a816c569','venue','207','best-seats',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Students stand in the risers. If you''re not in the student section, the spots are sections 116-117 and 216-217, and they expand for big games.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('5300ff44042402679ed8de25','venue','207','best-seats',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','If you''re not a student, the lower level is mostly donors. Buying from UNC directly usually only gets you upper level. Lower-level rights belong to donors, so it is resale only.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('1a7fd4549cd75f3a55412f8b','venue','207','atmosphere',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Weak for smaller games. The older donors do not bring much noise.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d0988a2d4e201d27f7d6ecf2','venue','207','atmosphere',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','But for ranked opponents and Duke, the student section expands and it gets loud.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('aed663e9e80c48252f25c8d1','venue','207','atmosphere',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Not a small college gym feel. More of an NBA vibe.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('a48d9a1e5a444e166206e43d','venue','207','food',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Not great, and the alcohol is expensive.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('2436aecf0ceda3f0fea00c60','venue','207','food',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','Nearby options: Crumbl, Alpaca, Chick-fil-A, and Domino''s.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('d38db11fab05212de456ecc8','venue','207','tips',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','One concourse serves both levels and it is small, so it gets packed at halftime. Go before or after.','2026-06-29T15:55:41.284Z');
INSERT OR REPLACE INTO tips (id,scope,target_id,section,user_id,author,body,created_at) VALUES ('f15469d410329e1cdbf18dd1','venue','207','tips',(SELECT id FROM users WHERE username = 'akash8' COLLATE NOCASE),'akash8','The Carolina Basketball Museum is next door, with really cool artifacts.','2026-06-29T15:55:41.284Z');
